// PaymentTimestampHandler.java (SOAP Handler for WS-Security Timestamp)
class PaymentTimestampHandler implements javax.xml.ws.handler.soap.SOAPHandler<SOAPMessageContext> {

    private static final Logger LOGGER = Logger.getLogger(PaymentTimestampHandler.class.getName());

    private static final String WSU_NAMESPACE = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd";
    private static final String WSSE_NAMESPACE = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd";

    // Replay cache: stores (createdTimestamp -> expiresTimestamp)
    private static final ConcurrentHashMap<String, Instant> replayCache = new ConcurrentHashMap<>();
    private static final long CLOCK_SKEW_TOLERANCE_SECONDS = 5; // Allow for 5 seconds clock skew

    // Static initializer block for periodic cleanup of expired timestamps
    static {
        Thread cleanupThread = new Thread(() -> {
            while (true) {
                try {
                    Thread.sleep(60 * 1000); // Clean up every minute
                    LOGGER.info("Running timestamp replay cache cleanup. Cache size before: " + replayCache.size());
                    Instant now = Instant.now();
                    replayCache.entrySet().removeIf(entry -> entry.getValue().plusSeconds(CLOCK_SKEW_TOLERANCE_SECONDS).isBefore(now));
                    LOGGER.info("Timestamp replay cache cleanup finished. Cache size after: " + replayCache.size());
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                    LOGGER.log(Level.WARNING, "Timestamp cleanup thread interrupted.", e);
                    break;
                } catch (Exception e) {
                    LOGGER.log(Level.SEVERE, "Error during timestamp cleanup.", e);
                }
            }
        });
        cleanupThread.setDaemon(true);
        cleanupThread.setName("TimestampCacheCleanupThread");
        cleanupThread.start();
    }

    @Override
    public Set<QName> getHeaders() {
        return Collections.singleton(new QName(WSSE_NAMESPACE, "Security"));
    }

    @Override
    public boolean handleMessage(SOAPMessageContext context) {
        Boolean outboundProperty = (Boolean) context.get(MessageContext.MESSAGE_OUTBOUND_PROPERTY);

        if (outboundProperty != null && outboundProperty.booleanValue()) {
            return true; // Outbound message (response), no replay protection needed
        }

        // Inbound message (request)
        try {
            SOAPMessage soapMessage = context.getMessage();
            SOAPHeader header = soapMessage.getSOAPHeader();

            if (header == null) {
                LOGGER.warning("SOAP message has no header. WS-Security timestamp not found.");
                throw new SOAPFaultException(SOAPFactory.newInstance().createFault("SOAP header is missing.", "Client"));
            }

            // Find wsse:Security element
            QName securityQName = new QName(WSSE_NAMESPACE, "Security", "wsse");
            Iterator<SOAPElement> securityElements = header.getChildElements(securityQName);

            if (!securityElements.hasNext()) {
                LOGGER.warning("WS-Security header (wsse:Security) not found.");
                throw new SOAPFaultException(SOAPFactory.newInstance().createFault("WS-Security header missing.", "Client"));
            }

            SOAPElement securityElement = securityElements.next();
            
            // Check for soapenv:mustUnderstand="1" on wsse:Security (optional, but good practice for security headers)
            String mustUnderstand = securityElement.getAttributeNS("http://schemas.xmlsoap.org/soap/envelope/", "mustUnderstand");
            if (!"1".equals(mustUnderstand) && !"true".equals(mustUnderstand)) { // JAX-WS might convert "1" to "true"
                 LOGGER.warning("WS-Security header mustUnderstand attribute is not set to 1.");
                 // Depending on policy, this might be a fault. For this example, we'll continue.
            }

            // Find wsu:Timestamp element within wsse:Security
            QName timestampQName = new QName(WSU_NAMESPACE, "Timestamp", "wsu");
            Iterator<SOAPElement> timestampElements = securityElement.getChildElements(timestampQName);

            if (!timestampElements.hasNext()) {
                LOGGER.warning("WS-Security Timestamp element (wsu:Timestamp) not found.");
                throw new SOAPFaultException(SOAPFactory.newInstance().createFault("WS-Security Timestamp missing.", "Client"));
            }

            SOAPElement timestampElement = timestampElements.next();

            // Extract wsu:Created and wsu:Expires
            QName createdQName = new QName(WSU_NAMESPACE, "Created", "wsu");
            QName expiresQName = new QName(WSU_NAMESPACE, "Expires", "wsu");

            Iterator<SOAPElement> createdIterator = timestampElement.getChildElements(createdQName);
            Iterator<SOAPElement> expiresIterator = timestampElement.getChildElements(expiresQName);

            if (!createdIterator.hasNext() || !expiresIterator.hasNext()) {
                LOGGER.warning("Missing wsu:Created or wsu:Expires within wsu:Timestamp.");
                throw new SOAPFaultException(SOAPFactory.newInstance().createFault("Malformed WS-Security Timestamp.", "Client"));
            }

            SOAPElement createdElement = createdIterator.next();
            SOAPElement expiresElement = expiresIterator.next();

            String createdStr = createdElement.getValue();
            String expiresStr = expiresElement.getValue();

            LOGGER.info("Extracted Timestamp - Created: " + createdStr + ", Expires: " + expiresStr);

            Instant createdInstant;
            Instant expiresInstant;
            try {
                createdInstant = Instant.parse(createdStr);
                expiresInstant = Instant.parse(expiresStr);
            } catch (DateTimeParseException e) {
                LOGGER.log(Level.WARNING, "Invalid timestamp format: " + e.getMessage(), e);
                throw new SOAPFaultException(SOAPFactory.newInstance().createFault("Invalid timestamp format. Must be ISO 8601 UTC.", "Client"));
            }

            Instant now = Instant.now();

            // Replay protection logic
            if (replayCache.containsKey(createdStr)) {
                LOGGER.warning("Replay detected for timestamp: " + createdStr);
                throw new SOAPFaultException(SOAPFactory.newInstance().createFault("Replay detected for timestamp: " + createdStr, "Server"));
            }

            // Check if timestamp is too old (created time is before now minus expiration + tolerance)
            // This prevents very old, but non-expired, timestamps from being processed if the 'Expires' is very far in the future
            // A common policy is to reject messages older than, say, 5 minutes, regardless of 'Expires'
            long maxAgeSeconds = 300; // e.g., 5 minutes
            if (createdInstant.plusSeconds(maxAgeSeconds).isBefore(now)) {
                LOGGER.warning("Timestamp created too long ago: " + createdStr + " (Max age: " + maxAgeSeconds + "s)");
                throw new SOAPFaultException(SOAPFactory.newInstance().createFault("Message is too old.", "Client"));
            }

            // Check if timestamp has expired (allowing for clock skew)
            if (expiresInstant.plusSeconds(CLOCK_SKEW_TOLERANCE_SECONDS).isBefore(now)) {
                LOGGER.warning("Timestamp has expired: " + createdStr + " (Expires: " + expiresStr + ", Current: " + now + ", Tolerance: " + CLOCK_SKEW_TOLERANCE_SECONDS + "s)");
                throw new SOAPFaultException(SOAPFactory.newInstance().createFault("Timestamp expired.", "Client"));
            }

            // Timestamp is valid and not a replay, add to cache
            replayCache.put(createdStr, expiresInstant);
            LOGGER.info("Timestamp " + createdStr + " processed successfully and added to replay cache.");

            // Put the timestamp details into the message context for the service endpoint (optional)
            context.put("com.example.paymentgateway.wsu.Created", createdStr);
            context.put("com.example.paymentgateway.wsu.Expires", expiresStr);
            context.setScope("com.example.paymentgateway.wsu.Created", MessageContext.Scope.APPLICATION);
            context.setScope("com.example.paymentgateway.wsu.Expires", MessageContext.Scope.APPLICATION);

        } catch (SOAPFaultException e) {
            LOGGER.log(Level.WARNING, "SOAP Fault during timestamp handling: " + e.getFault().getFaultString());
            throw e;
        } catch (SOAPException e) {
            LOGGER.log(Level.SEVERE, "SOAP Error during timestamp handling: " + e.getMessage(), e);
            try {
                throw new SOAPFaultException(SOAPFactory.newInstance().createFault("Server error during security processing.", "Server"));
            } catch (SOAPException ex) {
                throw new RuntimeException("Failed to create SOAP fault after internal SOAP error", ex);
            }
        } catch (Exception e) {
            LOGGER.log(Level.SEVERE, "Unexpected error during timestamp handling: " + e.getMessage(), e);
            try {
                throw new SOAPFaultException(SOAPFactory.newInstance().createFault("Internal server error during security processing.", "Server"));
            } catch (SOAPException ex) {
                throw new RuntimeException("Failed to create SOAP fault after unexpected error", ex);
            }
        }
        return true;
    }

    @Override
    public boolean handleFault(SOAPMessageContext context) {
        LOGGER.log(Level.WARNING, "Fault occurred in PaymentTimestampHandler while processing message.");
        return true;
    }

    @Override
    public void close(MessageContext context) {
        // No specific resources to close for this handler, but good to have.
    }
}

