class PaymentServicePublisher {

    private static final String SERVICE_URL = "http://localhost:8080/paymentService";
    private static final Logger LOGGER = Logger.getLogger(PaymentServicePublisher.class.getName());

    public static void main(String[] args) {
        LOGGER.info("Starting PaymentProcessingService...");
        PaymentProcessingServiceImpl implementor = new PaymentProcessingServiceImpl();

        Endpoint endpoint = Endpoint.create(implementor);

        // Attach the custom HandlerResolver to the endpoint
        endpoint.setHandlerResolver(new PaymentServiceHandlerResolver());

        endpoint.publish(SERVICE_URL);
        LOGGER.info("PaymentProcessingService published at: " + SERVICE_URL);
        LOGGER.info("Service is now running. Press Ctrl+C to stop.");

        // Add a shutdown hook to stop the endpoint gracefully
        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            if (endpoint != null && endpoint.isPublished()) {
                endpoint.stop();
                LOGGER.info("PaymentProcessingService stopped.");
            }
        }));
    }
}